# main.tf — Web app infrastructure
provider "aws" {
  region = var.region
}

module "vpc" {
  source      = "./modules/vpc"
  vpc_cidr    = "10.0.0.0/16"
  environment = var.environment
}

module "web" {
  source      = "./modules/web"
  vpc_id      = module.vpc.vpc_id
  subnet_ids  = module.vpc.public_subnet_ids
  instance_count = var.web_instance_count
}

module "database" {
  source        = "./modules/database"
  vpc_id        = module.vpc.vpc_id
  subnet_ids    = module.vpc.private_subnet_ids
  db_name       = var.db_name
  db_password   = var.db_password
}

# variables.tf
variable "region" { default = "us-east-1" }
variable "environment" { default = "production" }
variable "web_instance_count" { default = 2 }
variable "db_name" { default = "myapp" }
variable "db_password" { sensitive = true }

# provisioners.tf — Post-deployment configuration
resource "aws_instance" "web" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t3.micro"

  # Upload a configuration file
  provisioner "file" {
    source      = "app.conf"
    destination = "/tmp/app.conf"

    connection {
      type        = "ssh"
      user        = "ubuntu"
      private_key = file("~/.ssh/id_rsa")
      host        = self.public_ip
    }
  }

  # Run a remote script
  provisioner "remote-exec" {
    inline = [
      "sudo apt update -y",
      "sudo apt install -y nginx",
      "sudo systemctl start nginx",
    ]

    connection {
      type = "ssh"
      user = "ubuntu"
      private_key = file("~/.ssh/id_rsa")
      host = self.public_ip
    }
  }
}

# data-sources.tf — Read existing resources

# Get the latest Ubuntu AMI
data "aws_ami" "ubuntu" {
  most_recent = true
  owners      = ["099720109477"]

  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu-22.04-*-server-*"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# Get existing VPC and subnets
data "aws_vpc" "existing" {
  tags = {
    Name = "production-vpc"
  }
}

data "aws_subnets" "private" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.existing.id]
  }
}

# Use data sources in resources
resource "aws_instance" "app" {
  ami           = data.aws_ami.ubuntu.id
  subnet_id     = data.aws_subnets.private.ids[0]
}

# sentinel.hcl — Sentinel policies for Terraform Cloud

# Policy: enforce resource tags
import "tfplan/v2" as tfplan

# Ensure all resources have required tags
required_tags = ["Environment", "Owner", "CostCenter"]

main = rule {
  all tfplan.resource_changes as _, rc {
    rc.mode == "destroyed" or all required_tags as _, tag {
      rc.change.after.tags else {} contains tag
    }
  }
}

# Policy: prevent large instance types in non-prod
large_instances = ["m5.4xlarge", "c5.4xlarge", "r5.4xlarge"]

restrict_non_prod = rule {
  all tfplan.resource_changes as _, rc {
    rc.change.after.instance_type else "" not in large_instances
  }
}

# Policy: enforce encryption
require_encryption = rule {
  all tfplan.resource_changes as _, rc {
    rc.change.after.encrypted else true
  }
}
